#!/usr/bin/env node

/**
 * Scan Toff Neo4j descriptions for Gemini "thinking-leak" output.
 *
 * Read-only by default вЂ” lists every Toff product whose description was
 * generated by THIS software (descriptionSource в€€ {ai_reformat, ai_rewrite,
 * ai_image*, google_search_*}) AND whose text matches one of the
 * thinking-leak patterns from looksLikeThinkingLeak() in
 * apps/api/src/sync/services/ai-product-description.js.
 *
 * Manual descriptions (descriptionSource = "original") are NEVER scanned
 * (they're untouchable), and ai_reformat is the highest-priority source
 * because that's where the recent Fear Of God hoodie incident came from.
 *
 * Usage:
 *   node apps/api/src/scripts/scan-toff-thinking-leaks.js                    # dry-run, all our sources
 *   node apps/api/src/scripts/scan-toff-thinking-leaks.js --source ai_reformat
 *   node apps/api/src/scripts/scan-toff-thinking-leaks.js --limit 50
 *   node apps/api/src/scripts/scan-toff-thinking-leaks.js --json > leaks.json
 *   node apps/api/src/scripts/scan-toff-thinking-leaks.js --csv  > leaks.csv
 *   node apps/api/src/scripts/scan-toff-thinking-leaks.js --verbose          # also print the offending text head
 *
 * Output: a table with handle, source, leak reason, description preview,
 * and a clickable toff.ro URL so you can eyeball each one.
 *
 * This script does NOT modify Neo4j or VTEX. To fix flagged products,
 * pass the handles into regen-toff-descriptions.js (which now uses the
 * thinking-leak guard + retry).
 */

import dotenv from "dotenv";
import { fileURLToPath } from "url";
import path from "path";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
dotenv.config({ path: path.resolve(__dirname, "../../../../.env") });

import neo4j from "neo4j-driver";
import { NEO4J_URI, NEO4J_USER, NEO4J_PASSWORD } from "../sync/services/config.js";
import { looksLikeThinkingLeak } from "../sync/services/ai-product-description.js";

// в”Ђв”Ђв”Ђ Config в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

const accountName = process.env.VTEX_ACCOUNT || "toffro";
const STORE_ID = `${accountName}.vtexcommercestable.com.br`;

// в”Ђв”Ђв”Ђ CLI args в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

const args = process.argv.slice(2);
const limitIdx = args.indexOf("--limit");
const limit = limitIdx !== -1 ? parseInt(args[limitIdx + 1], 10) : null;
const sourceIdx = args.indexOf("--source");
const sourceFilter = sourceIdx !== -1 ? args[sourceIdx + 1] : null;
const asJson = args.includes("--json");
const asCsv = args.includes("--csv");
const verbose = args.includes("--verbose") || args.includes("-v");

// Same set as regen-toff-descriptions.js вЂ” only descriptions generated by us.
const OUR_SOURCES_CYPHER = `(
  p.descriptionSource STARTS WITH 'google_search_'
  OR p.descriptionSource STARTS WITH 'ai_image'
  OR p.descriptionSource = 'ai_rewrite'
  OR p.descriptionSource = 'ai_reformat'
)`;

// в”Ђв”Ђв”Ђ Reasons (same families as the validator, but here we want to LABEL,
//      not just true/false, so we re-check with named reasons) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

const REASONS = [
  // start-of-text patterns
  { name: "starts_with_thoughtful",     test: t => /^thoughtful\b/i.test(t.slice(0, 120)) },
  { name: "starts_with_okay_alright",   test: t => /^(okay|alright)[,!:\s]/i.test(t.slice(0, 120)) },
  { name: "starts_with_wait_let_me",    test: t => /^(wait|let me)\b/i.test(t.slice(0, 120)) },
  { name: "starts_with_meta_user",      test: t => /^the user (wants|asks|needs|provided|gave)/i.test(t.slice(0, 120)) },
  { name: "starts_with_heres_based_on", test: t => /^(here(?:'|')?s|based on (?:the|your)|looking at|first[,!:\s]|so[,!:\s]|hmm[,!.:\s])/i.test(t.slice(0, 120)) },
  { name: "starts_with_meta_marker",    test: t => /^\*\s*(intro|characteristics|composition|refining|double[\s-]check|final|correction|revised|wait|note)\b/i.test(t.slice(0, 120)) },
  // phrases anywhere
  { name: "phrase_wait_refining",       test: t => /\*\s*(wait[,\s]|refining\b|revised\b)/i.test(t) },
  { name: "phrase_double_check",        test: t => /\*\s*double[\s-]check\b/i.test(t) },
  { name: "phrase_final_check",         test: t => /\*\s*final\s+(check|version|structure|answer)/i.test(t) || /final check on (forbidden|banned)/i.test(t) },
  { name: "phrase_correction",          test: t => /\*\s*correction\b/i.test(t) },
  { name: "phrase_let_me_reread",       test: t => /let me re-?read/i.test(t) },
  { name: "phrase_looking_at_source",   test: t => /looking at the (source|prompt|rules)/i.test(t) },
  { name: "phrase_source_says",         test: t => /the (source|prompt) (says|didn'?t|did not|provided)/i.test(t) },
  { name: "phrase_one_more_check",      test: t => /one (more|small|last) (check|detail|thing)/i.test(t) },
  { name: "phrase_example_a_b",         test: t => /\bexample\s+[ab]\b/i.test(t) },
  { name: "duplicate_compozitie",       test: t => /\bcompozi[И›t]ie produs:[\s\S]*compozi[И›t]ie produs:/i.test(t) },
  // banned-word echoes from the rules block
  { name: "rule_echo_croitorie",        test: t => /piese de croitorie relaxat[Дѓa]/i.test(t) },
  { name: "rule_echo_vГўrf_migdalat",    test: t => /vГўrf migdalat/i.test(t) },
  { name: "rule_echo_haute_couture",    test: t => /haute couture/i.test(t) },
  // rule-block headers leaking verbatim
  { name: "rule_header_interzise",      test: t => /CUVINTE\s*\/\s*EXPRESII INTERZISE/i.test(t) },
  { name: "rule_header_structura",      test: t => /STRUCTURД‚\s*\(obligatorie/i.test(t) },
  { name: "rule_header_piele",          test: t => /\bREGULI PIELE\b/i.test(t) },
  { name: "rule_header_acord",          test: t => /\bACORD GRAMATICAL\b/i.test(t) },
  { name: "rule_header_toff_rules",     test: t => /TOFF (DESCRIPTION|SEO) RULES/i.test(t) },
];

function classifyLeak(text) {
  if (!text || typeof text !== "string") return [];
  const trimmed = text.trim();
  const matched = [];
  for (const r of REASONS) {
    try {
      if (r.test(trimmed)) matched.push(r.name);
    } catch {}
  }
  return matched;
}

// в”Ђв”Ђв”Ђ Neo4j fetch в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function getDriver() {
  return neo4j.driver(NEO4J_URI, neo4j.auth.basic(NEO4J_USER, NEO4J_PASSWORD));
}

async function fetchProducts() {
  const driver = getDriver();
  const session = driver.session();
  try {
    const sourceClause = sourceFilter
      ? `p.descriptionSource = $sourceFilter`
      : OUR_SOURCES_CYPHER;
    const limitClause = limit ? `LIMIT ${limit}` : "";

    const r = await session.run(
      `MATCH (p:Product)
       WHERE p.storeId = $storeId
         AND p.descriptionSource IS NOT NULL
         AND ${sourceClause}
         AND p.description IS NOT NULL
         AND size(trim(p.description)) >= 30
       RETURN p.id AS id, p.title AS title, p.handle AS handle,
              p.descriptionSource AS source, p.description AS description,
              p.updated_at AS updatedAt
       ORDER BY p.updated_at DESC
       ${limitClause}`,
      sourceFilter ? { storeId: STORE_ID, sourceFilter } : { storeId: STORE_ID }
    );

    return r.records.map(rec => ({
      id: rec.get("id"),
      title: rec.get("title"),
      handle: rec.get("handle"),
      source: rec.get("source"),
      description: rec.get("description"),
      updatedAt: rec.get("updatedAt"),
    }));
  } finally {
    await session.close();
    await driver.close();
  }
}

// в”Ђв”Ђв”Ђ Output formatters в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function buildUrl(handle) {
  return handle ? `https://www.toff.ro/${handle}/p` : "(no handle)";
}

function preview(text, n = 120) {
  return (text || "").replace(/\s+/g, " ").trim().slice(0, n);
}

function escapeCsv(s) {
  const v = String(s ?? "");
  if (/[",\n]/.test(v)) return `"${v.replace(/"/g, '""')}"`;
  return v;
}

// в”Ђв”Ђв”Ђ Main в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

async function main() {
  if (!asJson && !asCsv) {
    console.log(`\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ`);
    console.log(`  Scan Toff Descriptions for Thinking Leaks (READ-ONLY)`);
    console.log(`  Store:        ${STORE_ID}`);
    console.log(`  Source:       ${sourceFilter || "all our sources (ai_reformat, ai_rewrite, ai_image*, google_search_*)"}`);
    if (limit) console.log(`  Limit:        ${limit} products`);
    console.log(`в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n`);
    console.log(`[1] Fetching products from Neo4jвЂ¦`);
  }

  const products = await fetchProducts();

  if (!asJson && !asCsv) {
    console.log(`    Loaded ${products.length} products with our descriptions.\n`);
    console.log(`[2] Classifying with looksLikeThinkingLeak()вЂ¦\n`);
  }

  const leaks = [];
  const sourceCounts = {};
  for (const p of products) {
    sourceCounts[p.source] = (sourceCounts[p.source] || 0) + 1;
    if (!looksLikeThinkingLeak(p.description)) continue;
    const reasons = classifyLeak(p.description);
    leaks.push({
      id: p.id,
      title: p.title,
      handle: p.handle,
      source: p.source,
      updatedAt: p.updatedAt,
      url: buildUrl(p.handle),
      length: p.description.length,
      reasons,
      preview: preview(p.description, 200),
    });
  }

  if (asJson) {
    process.stdout.write(JSON.stringify({ scanned: products.length, leakCount: leaks.length, leaks }, null, 2) + "\n");
    return;
  }

  if (asCsv) {
    const headers = ["id", "handle", "source", "updatedAt", "length", "reasons", "url", "title", "preview"];
    process.stdout.write(headers.join(",") + "\n");
    for (const l of leaks) {
      process.stdout.write([
        escapeCsv(l.id),
        escapeCsv(l.handle),
        escapeCsv(l.source),
        escapeCsv(l.updatedAt),
        escapeCsv(l.length),
        escapeCsv(l.reasons.join("|")),
        escapeCsv(l.url),
        escapeCsv(l.title),
        escapeCsv(l.preview),
      ].join(",") + "\n");
    }
    return;
  }

  // human-readable
  console.log(`в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ`);
  console.log(`  RESULTS`);
  console.log(`    Scanned:        ${products.length} products`);
  console.log(`    Leaks detected: ${leaks.length}`);
  console.log(`    Leak rate:      ${products.length ? ((leaks.length / products.length) * 100).toFixed(2) : "0.00"}%`);
  console.log(`в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ`);
  console.log(`\n  Per-source totals (all scanned, not just leaks):`);
  for (const [src, n] of Object.entries(sourceCounts).sort((a, b) => b[1] - a[1])) {
    console.log(`    ${src.padEnd(32)} ${n}`);
  }

  if (leaks.length === 0) {
    console.log(`\nвњ“ No leaks detected. Nothing to do.\n`);
    return;
  }

  // Per-source leak counts
  const leakBySrc = {};
  for (const l of leaks) leakBySrc[l.source] = (leakBySrc[l.source] || 0) + 1;
  console.log(`\n  Per-source LEAK counts:`);
  for (const [src, n] of Object.entries(leakBySrc).sort((a, b) => b[1] - a[1])) {
    console.log(`    ${src.padEnd(32)} ${n}`);
  }

  // Per-reason counts
  const reasonCounts = {};
  for (const l of leaks) {
    for (const r of l.reasons) reasonCounts[r] = (reasonCounts[r] || 0) + 1;
  }
  console.log(`\n  Per-reason counts (a leak can match multiple):`);
  for (const [r, n] of Object.entries(reasonCounts).sort((a, b) => b[1] - a[1])) {
    console.log(`    ${r.padEnd(32)} ${n}`);
  }

  console.log(`\n  Flagged products (most recent first):\n`);
  for (const [i, l] of leaks.entries()) {
    const idx = String(i + 1).padStart(String(leaks.length).length);
    console.log(`  [${idx}] "${l.title}"`);
    console.log(`        source:  ${l.source}    length: ${l.length}ch    updated: ${l.updatedAt || "вЂ”"}`);
    console.log(`        reasons: ${l.reasons.join(", ")}`);
    console.log(`        url:     ${l.url}`);
    if (verbose) {
      console.log(`        head:    "${l.preview}вЂ¦"`);
    }
    console.log();
  }

  console.log(`в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ`);
  console.log(`  Next step: re-run regen-toff-descriptions.js on the flagged`);
  console.log(`  handles. The new looksLikeThinkingLeak() guard + retry-with-`);
  console.log(`  thinkingBudget=0 will catch any leak this time around. Example:`);
  console.log(`    node apps/api/src/scripts/regen-toff-descriptions.js \\`);
  console.log(`      --handle ${leaks[0].handle}`);
  console.log(`в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n`);
}

main()
  .then(() => process.exit(0))
  .catch(e => {
    console.error("\nFatal error:", e);
    process.exit(1);
  });
